import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    { sender: "bot", text: "Hello 🌱" }
  ]);

  const [input, setInput] = useState("");
  const [hasGreeted, setHasGreeted] = useState(false);

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    /* ================= HAPPY SONGS ================= */
    const happySongs = `
🎶 Telugu:
• Butta Bomma  
• Samajavaragamana  
• Vachadayyo Saami  

🎶 Hindi:
• Ilahi – Yeh Jawaani Hai Deewani  
• Love You Zindagi – Dear Zindagi  
• Gallan Goodiyan  

🎶 English:
• Happy – Pharrell Williams  
• On Top of the World – Imagine Dragons  
• Good Life – OneRepublic
`;

    /* ================= GREETING ================= */
    if (!hasGreeted && ["hi", "hello", "hey", "hai"].includes(text)) {
      setHasGreeted(true);
      return "Hello 🌼 I’m here with you. Take your time.";
    }

    /* ================= HAPPY MOOD DETECTION ================= */
    if (
      text.includes("happy") ||
      text.includes("amazing") ||
      text.includes("great") ||
      text.includes("excited") ||
      text.includes("energetic") ||
      text.includes("positive")
    ) {
      return (
        "That’s wonderful to hear 😄🌸\n\n" +
        "You sound really cheerful today. What’s been making your day so special?"
      );
    }

    /* ================= HAPPY EVENTS ================= */
    if (
      text.includes("surprise") ||
      text.includes("friend") ||
      text.includes("celebrate") ||
      text.includes("fun")
    ) {
      return (
        "That sounds lovely 🥳✨\n\n" +
        "Moments like these remind us how meaningful connections and little joys can be.\n\n" +
        "Did you do anything special to enjoy this happiness?"
      );
    }

    /* ================= NATURE / SELF-CARE ================= */
    if (
      text.includes("walk") ||
      text.includes("park") ||
      text.includes("sunshine") ||
      text.includes("nature")
    ) {
      return (
        "That sounds so refreshing 🌞🌿\n\n" +
        "Fresh air and movement can instantly lift our mood. It’s great that you took time for yourself.\n\n" +
        "How did it make you feel afterward?"
      );
    }

    /* ================= JOY CONTINUATION ================= */
    if (
      text.includes("smiling") ||
      text.includes("joy") ||
      text.includes("positive")
    ) {
      return (
        "I can feel your happiness radiating through this chat 💛😊\n\n" +
        "Isn’t it amazing how these moments brighten everything around us?"
      );
    }

    /* ================= SUCCESS / ACHIEVEMENT ================= */
    if (
      text.includes("passed") ||
      text.includes("cleared") ||
      text.includes("success") ||
      (text.includes("exam") && text.includes("pass"))
    ) {
      return (
        "That’s fantastic news 🎉🌟\n\n" +
        "You should be really proud of yourself. Achievements like this deserve celebration!\n\n" +
        "Would you like to celebrate with some happy music? 🎶"
      );
    }

    /* ================= HAPPY SONG REQUEST ================= */
    if (text.includes("song") || text.includes("music")) {
      return (
        "Let’s keep the happy vibes going 🎶😄\n\n" +
        happySongs +
        "\nEnjoy these joyful tracks!"
      );
    }

    /* ================= STRESS (UNCHANGED) ================= */
    if (
      text.includes("stress") ||
      text.includes("stressed") ||
      text.includes("overwhelmed")
    ) {
      return (
        "I’m really sorry you’re feeling this way 🤍\n\n" +
        "Stress can come from studies, work, family, finances, health, or future worries.\n\n" +
        "What do you feel is causing this stress for you?"
      );
    }

    if (text.includes("study") || text.includes("exam") || text.includes("college")) {
      return "Academic pressure can be overwhelming. What part feels most difficult right now?";
    }

    if (text.includes("work") || text.includes("job")) {
      return "Work stress can be exhausting. Is it workload, deadlines, or expectations?";
    }

    if (text.includes("family")) {
      return "Family situations can feel heavy. What’s been happening?";
    }

    if (text.includes("money") || text.includes("financial")) {
      return "Financial concerns can be stressful. What’s worrying you the most?";
    }

    /* ================= DEFAULT ================= */
    return (
      "Thank you for sharing 🤍\n\n" +
      "I’m listening. You can tell me more whenever you’re ready."
    );
  };

  const handleSend = () => {
    if (!input.trim()) return;

    setMessages([
      ...messages,
      { sender: "user", text: input },
      { sender: "bot", text: therapistReply(input) }
    ]);
    setInput("");
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, i) => (
          <div key={i} className={`message-group ${msg.sender}`}>
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>{msg.text}</div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type here when you're ready..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
